// Certified numeric-loop fixture for the Betti → WASM emitter (scalar-v1):
// a single exported numeric function with an affine loop — recognized by the
// `numeric-loop` certified class in polyglot/src/aot_wasm.rs.
/**
 * Runs the gnosis command-line workflow.
 */
export function main(n: number): number {
  let acc = 0;
  for (let i = 0; i < n; i += 1) {
    acc = acc + i * i;
  }
  return acc;
}
